import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const ProductForm = () => {
    const [formData, setFormData] = useState({
        name: '',
        price: '',
        stock: '',
        description: '',
        image: '',
    });
    const navigate = useNavigate();

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        const reader = new FileReader();

        reader.onloadend = () => {
            setFormData({ ...formData, image: reader.result }); 
        };

        if (file) {
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        const formData = new FormData();
        formData.append('name', name);
        formData.append('price', price);
        formData.append('stock', stock);
        formData.append('description', description);
        if (imageFile) formData.append('image', imageFile);
    
        try {
            await axios.post('http://localhost:5000/api/products/add', formData, {
                headers: { 'Content-Type': 'multipart/form-data' },
            });
            alert('Product added successfully!');
            navigate('/admin/products'); // Redirect to product table
        } catch (error) {
            console.error('Error adding product:', error);
        }
    };
    

    return (
        <form onSubmit={handleSubmit}>
            <h2>Add Product</h2>
            <input name="name" type="text" placeholder="Name" value={formData.name} onChange={handleChange} required />
            <input name="price" type="number" placeholder="Price" value={formData.price} onChange={handleChange} required />
            <input name="stock" type="number" placeholder="Stock" value={formData.stock} onChange={handleChange} required />
            <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} required />
            <input name="image" type="file" onChange={handleFileChange} required />
            <button type="submit">Add Product</button>
        </form>
    );
};

export default ProductForm;
